/**
 * @module tools/return-to-router
 * Tool an agent uses to return the conversation to Router for fresh triage.
 *
 * Behavior:
 *   1. The tool result terminates the calling agent's turn immediately
 *      (`terminate: true`) so no more text is generated by the previous agent.
 *   2. It queues a root swap to Router and records a `pendingSwitchHandoff`
 *      containing the `reason` argument.
 *   3. The chat-session loop then applies the swap (rebuilding the root for
 *      Router) and re-enters the turn with `reason` as Router's first user
 *      message — so the conversation continues seamlessly.
 *
 * Because of (1), the `reason` argument is not just a justification — it IS the
 * first message Router sees. The tool/parameter descriptions are written to
 * push the LLM toward crafting a useful, self-contained triage prompt.
 */

import { Type } from "@earendil-works/pi-ai";
import { defineTool } from "@earendil-works/pi-coding-agent";
import { AGENTS } from "../constants.js";
import { setActiveAgent } from "../shared/session/agent-switching.js";
import { getAgentDisplayName, loadAgentDef } from "../shared/session/agents.js";

/**
 * Core logic for returning the active conversation to Router.
 *
 * @param {Object} params
 * @param {string} params.reason
 * @param {import('../shared/workflow/workflow.js').UiAPI | null | undefined} uiAPI
 * @param {import('../shared/session/hosted-session.js').HostedSession | null | undefined} hostedSession
 * @param {{ createAgentHandler?: (agentName: string, deps?: { hostedSession?: import('../shared/session/hosted-session.js').HostedSession }) => import('../shared/session/types.js').AgentMessageHandler }} [__deps]
 * @returns {Promise<import('@earendil-works/pi-coding-agent').AgentToolResult<{ agentName: string, reason: string } | null>>}
 */
export async function executeReturnToRouter(params, uiAPI, hostedSession, __deps) {
    const { reason } = params;

    if (!uiAPI || !hostedSession) {
        return {
            content: [{
                type: "text",
                text: `Error: This tool requires an active UI session to return to ${
                    getAgentDisplayName(AGENTS.ROUTER)
                }. Please ensure you're running in interactive mode.`,
            }],
            details: null,
        };
    }

    const routerDef = await loadAgentDef(AGENTS.ROUTER);
    const createAgentHandler = __deps?.createAgentHandler ||
        (await import("../shared/session/agent-handler.js")).createAgentHandler;
    const handler = createAgentHandler(AGENTS.ROUTER, { hostedSession });
    setActiveAgent(hostedSession, AGENTS.ROUTER, handler, uiAPI, routerDef.model || undefined);
    hostedSession.setPendingSwitchHandoff({ agentName: AGENTS.ROUTER, reason });

    return {
        content: [],
        details: { agentName: AGENTS.ROUTER, reason },
        terminate: true,
    };
}

/**
 * Tool for returning the active conversation to Router in the interactive session.
 */
export const returnToRouterTool = defineTool({
    name: "return_to_router",
    label: `Return to ${getAgentDisplayName(AGENTS.ROUTER)}`,
    description:
        `Return the conversation to ${
            getAgentDisplayName(AGENTS.ROUTER)
        } when the user's request needs fresh triage or is outside your ` +
        "role. Calling this tool ENDS your turn immediately — you will not generate any more text after the call. " +
        `The 'reason' argument is delivered to ${
            getAgentDisplayName(AGENTS.ROUTER)
        } as its first user message, so write it as a self-contained ` +
        `prompt that lets ${
            getAgentDisplayName(AGENTS.ROUTER)
        } continue the conversation without seeing your prior turn.`,
    parameters: Type.Object({
        reason: Type.String({
            description:
                `The first user message ${
                    getAgentDisplayName(AGENTS.ROUTER)
                } will receive. Restate the user's ask in your own words and ` +
                `include any context ${getAgentDisplayName(AGENTS.ROUTER)} needs to triage it \u2014 ${
                    getAgentDisplayName(AGENTS.ROUTER)
                } does not see your prior reasoning. Address ` +
                `${
                    getAgentDisplayName(AGENTS.ROUTER)
                } in the second person (e.g. 'The user wants you to ...'). Do NOT write a justification for ` +
                "leaving your role.",
        }),
    }),
    execute(_toolCallId, params, _signal, _onUpdate, context) {
        const toolContext =
            /** @type {{ uiAPI?: import('../shared/workflow/workflow.js').UiAPI, hostedSession?: import('../shared/session/hosted-session.js').HostedSession }} */ (context ||
                {});
        return executeReturnToRouter(
            /** @type {{ reason: string }} */ (params),
            toolContext.uiAPI,
            toolContext.hostedSession,
        );
    },
});
